import React, { useState, useEffect } from "react";

// Components
import Intro from "./Components/Intro";
import Login from "./Components/Login";
import Signup from "./Components/Signup";
import ForgotPassword from "./Components/ForgotPassword";
import HomePage from "./Components/HomePage";
import Mission from "./Components/Mission";

function App() {
  const [page, setPage] = useState("intro");
  const [fadeOut, setFadeOut] = useState(false);

  // Intro animation timeout
  useEffect(() => {
    const timer1 = setTimeout(() => setFadeOut(true), 2500);
    const timer2 = setTimeout(() => setPage("login"), 3500);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  return (
    <div>
      {/* Intro Page */}
      {page === "intro" && <Intro fadeOut={fadeOut} />}

      {/* Login Page */}
      {page === "login" && (
        <Login
          toggleSignup={() => setPage("signup")}
          goForgot={() => setPage("forgot")}
          goHome={() => setPage("home")}
        />
      )}

      {/* Signup Page */}
      {page === "signup" && <Signup toggleLogin={() => setPage("login")} />}

      {/* Forgot Password Page */}
      {page === "forgot" && (
        <ForgotPassword toggleLogin={() => setPage("login")} />
      )}

      {/* Home Page */}
      {page === "home" && <HomePage goMission={() => setPage("ission")} />}

      {/* Mission Page */}
      {page === "mission" && <Mission />}
    </div>
  );
}

export default App;
